const express = require("express");
const router  = express.Router();
const Booking = require("../models/Booking");
const Vehicle = require("../models/Vehicle");

// POST /api/bookings/rent
// Body: { userId, vehicleId, hours }
// Calculates totalPrice = vehicle.pricePerHour * hours
router.post("/rent", async (req, res) => {
  try {
    const { userId, vehicleId, hours } = req.body;

    if (!userId || !vehicleId || !hours) {
      return res.status(400).json({ message: "userId, vehicleId and hours are required" });
    }

    const vehicle = await Vehicle.findById(vehicleId);
    if (!vehicle) {
      return res.status(404).json({ message: "Vehicle not found" });
    }

    const totalPrice = vehicle.pricePerHour * Number(hours);

    const booking = new Booking({
      userId,
      vehicleId,
      hours: Number(hours),
      totalPrice,
    });

    await booking.save();
    res.json(booking);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// GET /api/bookings/user/:userId
// Returns all bookings for a user, with vehicle details populated
router.get("/user/:userId", async (req, res) => {
  try {
    const bookings = await Booking.find({ userId: req.params.userId })
      .populate("vehicleId", "name type pricePerHour description")
      .sort({ bookingTime: -1 }); // newest first

    res.json(bookings);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

module.exports = router;